CREATE TABLE IF NOT EXISTS workspaces (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), name TEXT NOT NULL, owner_user_id UUID REFERENCES auth.users(id), created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS projects (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), workspace_id UUID REFERENCES workspaces(id), title TEXT NOT NULL, raw_idea TEXT, project_type TEXT, industry TEXT, status TEXT DEFAULT 'draft', clarity_score INTEGER DEFAULT 0, completeness_score INTEGER DEFAULT 0, logic_integrity_score INTEGER DEFAULT 0, edge_case_score INTEGER DEFAULT 0, build_readiness_score INTEGER DEFAULT 0, created_by UUID REFERENCES auth.users(id), created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW(), archived_at TIMESTAMPTZ);
CREATE TABLE IF NOT EXISTS spec_sections (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), project_id UUID REFERENCES projects(id) ON DELETE CASCADE, section_type TEXT NOT NULL, title TEXT NOT NULL, content TEXT, completeness_score INTEGER DEFAULT 0, status TEXT DEFAULT 'empty', order_index INTEGER NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS answers (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), project_id UUID REFERENCES projects(id) ON DELETE CASCADE, section_type TEXT NOT NULL, question_key TEXT NOT NULL, answer_text TEXT, updated_at TIMESTAMPTZ DEFAULT NOW(), UNIQUE(project_id, section_type, question_key));
CREATE TABLE IF NOT EXISTS exports (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), project_id UUID REFERENCES projects(id) ON DELETE CASCADE, export_type TEXT NOT NULL, content TEXT, created_at TIMESTAMPTZ DEFAULT NOW());
CREATE TABLE IF NOT EXISTS reviews (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), project_id UUID REFERENCES projects(id) ON DELETE CASCADE, section_type TEXT, severity TEXT, comment TEXT, status TEXT DEFAULT 'open', created_by UUID REFERENCES auth.users(id), created_at TIMESTAMPTZ DEFAULT NOW());
